mapper.insert:
insert into permission (id, name, code, type, path, parent_id) values
(#{item.id}, #{item.name}, #{item.code}, #{item.type}, #{item.path}, #{item.parentId})
on duplicate key update name = #{item.name}, code = #{item.code}, type = #{item.type}, path = #{item.path}, parent_id = #{item.parentId}
